  'Transporte Público','Aluguel','Condomínio','Energia Elétrica',
  'Água / Saneamento','Internet / TV','Gás','Farmácia',
  'Médico / Consulta','Plano de Saúde','Academia / Esporte',
  'Mensalidade Escola','Curso / Capacitação','Livros / Material',
  'Compras','Roupas / Calçados','Eletrônicos','Lazer / Entretenimento',
  'Streaming','Viagem / Hotel','Financeiro','Fatura Cartão',
  'Empréstimo / Parcela','Seguro','Investimento','Imposto / Taxa',
  'Serviços','Assinatura','Telefone / Celular','Pet','Doação / Caridade',
  'Outros (despesa)','Salário','Freelance / Serviço','Aluguel Recebido',
  'Investimento / Rendimento','Reembolso','Presente / Doação','Venda',
  'Cashback / Desconto','Outros (receita)','Receita'
]);

const INVALIDAS = new Set([
  'entrada','saida','saída','gasto','gastos','despesa','despesas',
  'receita','receitas','debito','débito','credito','crédito',
  'expense','income','debit','credit','pagamento','payment',
  'transferencia','transferência','movimentacao','movimentação',
  'compra','venda como direcao','pix','ted','doc','boleto'
]);

function norm(str) {
  return String(str || '')
    .trim()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

function buscarValida(raw) {
  const n = norm(raw);
  for (const v of VALIDAS) {
    if (norm(v) === n) return v;
  }
  return null;
}

function inferirPorTexto(texto) {
  const t = norm(texto);

