    return 'Receita';

  // Alimentação
  if (/mercado|supermercad|hortifrut|acougue|mercearia|minimercado/.test(t))
    return 'Mercado';
  if (/restaur|self.?service|churrascar|pizzar|hamburguer|burger|sushi|japonesa|italiana|culinaria|almoco|jantar|refeicao|lanchonete|snack|comida/.test(t))
    return 'Restaurante';
  if (/ifood|rappi|uber.?eat|delivery|marmita|quentinha/.test(t))
    return 'Delivery';
  if (/padaria|confeitaria|cafeteria|boulangerie/.test(t))
    return 'Padaria / Café';

  // Transporte
  if (/uber|99|cabify|taxi/.test(t)) return 'Uber / Táxi';
  if (/combustiv|gasolina|etanol|diesel|abastec|posto/.test(t)) return 'Combustível';
  if (/estacionam|parking|zona.?azul/.test(t)) return 'Estacionamento';
  if (/manutenc|funilaria|mecanica|borracharia|autocentro|troca.?oleo/.test(t)) return 'Manutenção Veículo';
  if (/metro|onibus|brt|trem|bilhete.?unico/.test(t)) return 'Transporte Público';

  // Moradia
  if (/aluguel|locac/.test(t)) return 'Aluguel';
  if (/condomin|sindico|taxa.?cond/.test(t)) return 'Condomínio';
  if (/energia|eletric|luz|kwh|distribuid/.test(t)) return 'Energia Elétrica';
  if (/agua|esgoto|saneam|hidromet/.test(t)) return 'Água / Saneamento';
  if (/internet|fibra|banda.?larg|wi.?fi|tv.?a.?cabo/.test(t)) return 'Internet / TV';
  if (/telefon|celular|movel|chip|sinal|plano.?(cel|mob)/.test(t)) return 'Telefone / Celular';
  if (/\bgas\b|glp|botijao|gasoduto/.test(t)) return 'Gás';
  if (/iptu|taxa.?imov/.test(t)) return 'Imposto / Taxa';

  // Saúde
  if (/farmac|drogari|remedio|medicam/.test(t)) return 'Farmácia';
  if (/medico|medica|consulta|clinica|hospital|pronto.?socorro/.test(t)) return 'Médico / Consulta';
  if (/plano.?saude|convenio|unimed|amil|hapvida/.test(t)) return 'Plano de Saúde';
  if (/academia|ginasio|crossfit|natacao|esporte/.test(t)) return 'Academia / Esporte';

  // Educação
  if (/escola|colegio/.test(t)) return 'Mensalidade Escola';
  if (/faculdad|universid|graduac|pos.?grad|ead|curso|capacitac|treinamento|idioma/.test(t)) return 'Curso / Capacitação';
  if (/livro|apostila|material.?escolar/.test(t)) return 'Livros / Material';

  // Lazer e assinaturas
  if (/netflix|spotify|amazon.?prime|disney|hbo|globo.?play|paramount|apple.?tv|deezer/.test(t)) return 'Streaming';
  if (/assinatura|mensalid.?(club|assin|plataform)/.test(t)) return 'Assinatura';
  if (/cinema|teatro|show|ingresso|parque|museu|evento/.test(t)) return 'Lazer / Entretenimento';
  if (/hotel|pousada|hostel|airbnb|hospedagem|passagem|aereo/.test(t)) return 'Viagem / Hotel';

  // Compras
  if (/roupa|calcado|tenis|sandalia|vestuario/.test(t)) return 'Roupas / Calçados';
  if (/eletronico|notebook|computad|tablet/.test(t)) return 'Eletrônicos';
  if (/amazon|shopee|magazine|americanas|casas.?bahia|submarino/.test(t)) return 'Compras';

  // Financeiro
  if (/fatura|cartao|credito/.test(t)) return 'Fatura Cartão';
  if (/emprestimo|parcela|financiam/.test(t)) return 'Empréstimo / Parcela';
  if (/seguro(?!.?saude)/.test(t)) return 'Seguro';
  if (/investim|aplicac|cdb|tesouro|fundo/.test(t)) return 'Investimento';
  if (/imposto|ipva|irpf|darf/.test(t)) return 'Imposto / Taxa';

  // Receitas
  if (/salario|pagamento.?recebido|folha/.test(t)) return 'Salário';
  if (/freelance|servico.?prest|honorario/.test(t)) return 'Freelance / Serviço';
  if (/aluguel.?recebido|renda.?imov/.test(t)) return 'Aluguel Recebido';
  if (/cashback|desconto.?recebido|reembolso/.test(t)) return 'Cashback / Desconto';
  if (/rendimento|dividendo|juros.?recebido/.test(t)) return 'Investimento / Rendimento';

  // Pets
  if (/\bpet\b|veterin|racao|animais/.test(t)) return 'Pet';

  return null;
}

function sanitizar(categoria, transacao) {
  const catNorm = norm(categoria);

  if (!categoria || catNorm === '') {
    return inferirPorTexto(transacao) || 'Outros';
  }

  if (INVALIDAS.has(catNorm)) {
    return inferirPorTexto(transacao) || 'Outros';
  }

  const match = buscarValida(categoria);
  if (match && match !== 'Outros' && match !== 'Outros (despesa)' && match !== 'Outros (receita)') return match;

  // Se categoria é 'Outros', tentar inferir algo melhor pelo texto
  if (match === 'Outros' || match === 'Outros (despesa)' || match === 'Outros (receita)') {
    const inferido = inferirPorTexto(transacao);
    if (inferido) return inferido;
    return match; // mantém Outros só se não conseguiu inferir
  }

  const inferDaCategoria = inferirPorTexto(categoria);
  if (inferDaCategoria) return inferDaCategoria;

  return inferirPorTexto(transacao) || 'Outros';
}

return [{ json: { ...data, categoria: sanitizar(data.categoria, data.transacao) } }];
} catch (e) {
  return [{ json: {
    success: false,
    error_code: 'CODE_ERROR',
    message: '[FN - Sanitiza Categoria] ' + (e.message || 'Erro desconhecido'),
    _original_error: String(e)
  }}];
}

try {
const data = $input.first().json;

if (data.success === false && data.error_code) {
  return [{ json: { ...data, inputs_validos: false, erros_validacao: [data.message] } }];
}

const erros = [];

if (!data.data_transacao || String(data.data_transacao).trim() === '') {
  erros.push('data_transacao é obrigatório');
}
if (!data.transacao || String(data.transacao).trim() === '') {
  erros.push('transacao é obrigatório');
}
if (!data.usuario_id || String(data.usuario_id).trim() === '') {
  erros.push('usuario_id é obrigatório');
}

if (erros.length > 0) {
  return [{
    json: {
      ...data,
      inputs_validos: false,
      erros_validacao: erros,
      _debug: {
        received_keys: data._raw_keys || [],
        source: data._source || 'unknown',
        data_transacao_value: data.data_transacao,
        transacao_value: data.transacao,
        usuario_id_value: data.usuario_id
      }
    }
  }];
}

return [{
  json: {
    ...data,
    inputs_validos: true,
    erros_validacao: erros
  }
}];
} catch (e) {
  return [{ json: {
    success: false,
    error_code: 'VALIDATE_ERROR',
    inputs_validos: false,
    erros_validacao: ['[FN - Valida Inputs] ' + (e.message || 'Erro desconhecido')]
  }}];
}

