try {
const data = $input.first().json;

if (data.success === false && data.error_code) {
  return [{ json: { ...data, inputs_validos: false, erros_validacao: [data.message] } }];
}

const erros = [];

if (!data.data_transacao || String(data.data_transacao).trim() === '') {
  erros.push('data_transacao é obrigatório');
}
if (!data.transacao || String(data.transacao).trim() === '') {
  erros.push('transacao é obrigatório');
}
if (!data.usuario_id || String(data.usuario_id).trim() === '') {
  erros.push('usuario_id é obrigatório');
}

if (erros.length > 0) {
  return [{
    json: {
      ...data,
      inputs_validos: false,
      erros_validacao: erros,
      _debug: {
        received_keys: data._raw_keys || [],
        source: data._source || 'unknown',
        data_transacao_value: data.data_transacao,
        transacao_value: data.transacao,
        usuario_id_value: data.usuario_id
      }
    }
  }];
}

return [{
  json: {
    ...data,
    inputs_validos: true,
    erros_validacao: erros
  }
}];
} catch (e) {
